function imgLst = fMspcDirLstV03(espcDir,nmbSht)% Function to get a list and number of images% for TREX magspec analysis%% [nmbImg,imgLst] = fMspcDirLstV02(espcDir,nmbSht)%% espcDir: a cell of directories to look for images% nmbSht: number of shots from trex logfile% nmbImg: number of images to go through% imgLst: image list (shot number)%% Kei Nakamura% Created on Monday, June 1st 2009.% Modified on Tuesday, April 13th 2010.% Modified on Tuesday, Feb 1st 2011.%% ver.2: to follow the change in the directory structure (4 separate folders)% ver.3: modify to analyze not complete set%% mainimgLst = zeros(nmbSht,6);   % image list matrix, shtNmb,cam0-4,logic ORimgLst(1:end,1) = [1:nmbSht]';  % first clm is shot numberimgLst(1:end,2) = fMspcShtLstV01(espcDir{1},nmbSht,0);    % get a list for cam0imgLst(1:end,3) = fMspcShtLstV01(espcDir{2},nmbSht,2);    % get a list for cam2imgLst(1:end,4) = fMspcShtLstV01(espcDir{3},nmbSht,3);    % get a list for cam3imgLst(1:end,5) = fMspcShtLstV01(espcDir{4},nmbSht,4);    % get a list for cam4imgLst(1:end,6) = imgLst(:,2)|imgLst(:,3)|imgLst(:,4)|imgLst(:,5);  % logic or
